/* Backward compat alias */
Object.defineProperty(window.SOB, 'inspectors', { get(){ return this.workers; }, set(v){ this.workers = v; }, enumerable: false });

/* Форматування чисел */
window.fmt = (n) => (typeof n === 'number' ? n.toLocaleString('uk-UA').replace(/,/g, ' ') : n);

/* XSS-екранування — використовувати при вставці даних з бази через innerHTML */
window.esc = (s) => String(s ?? '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;');

/* Розрахунок охоплення учнів для закладу
   Повертає: { events, participations, uniqueStudents, coveragePercent, totalStudents }
   uniqueStudents = min(participations, totalStudents) — не може перевищувати кількість учнів */
window.calcCoverage = (school) => {
  const totalStudents = school.students || 0;
  const events        = school.events || 0;
  const participations= school.participants || 0;
  const uniqueStudents= totalStudents > 0 ? Math.min(participations, totalStudents) : participations;
  const coveragePercent = totalStudents > 0 ? Math.round((uniqueStudents / totalStudents) * 100) : 0;
  return { events, participations, uniqueStudents, coveragePercent, totalStudents };
};

/* Місячний графік: історичні дані (Excel) + платформні заходи з журналу */
window.calcMonthlyChart = () => {
  const eb = window.SOB.charts?.eventsByMonth || {};
  const labels = [...(eb.labels || [])];
  const events = [...(eb.events || [])];
  const participants = [...(eb.participants || [])];

  const evs = (window.SOB.schoolEvents || []).filter(e => e.status !== 'cancelled' && e.date);
  if (!evs.length) return { labels, events, participants };

  const MN = ['Січ','Лют','Бер','Кві','Тра','Чер','Лип','Сер','Вер','Жов','Лис','Гру'];
  const byMonth = {};
  evs.forEach(e => {
    const d = new Date(e.date);
    if (isNaN(d)) return;
    const lbl = MN[d.getMonth()];
    if (!byMonth[lbl]) byMonth[lbl] = { events: 0, participants: 0 };
    byMonth[lbl].events++;
    byMonth[lbl].participants += (e.participants || 0);
  });

  Object.entries(byMonth).forEach(([lbl, m]) => {
    const idx = labels.indexOf(lbl);
    if (idx >= 0) {
      events[idx] += m.events;
      participants[idx] = (participants[idx] || 0) + m.participants;
    } else {
      labels.push(lbl);
      events.push(m.events);
      participants.push(m.participants);
    }
  });
  return { labels, events, participants };
};

/* ============================================================
   Централізований модуль статистики — єдине джерело правди
   Всі сторінки використовують ці функції, дублювання заборонено
   ============================================================ */

/* Агрегована статистика по списку закладів.
   Якщо передано events — перераховує динамічно з журналу (для фільтрів дат).
   Без events — використовує статичні поля (base + всі журнальні). */
window.calcStats = (schools, events) => {
  if (!schools) schools = (window.SOB.schools || []).filter(s => s.serviced);
  const prevTypes = ['prevention','mine','evacuation','cyber','buling','legal'];

  if (events !== undefined) {
    /* Режим: динамічний підрахунок з переданого масиву заходів */
    const schoolIds = new Set(schools.map(s => s.id));
    const evs = events.filter(e => schoolIds.has(e.schoolId));
    const totalStudents  = schools.reduce((a, s) => a + (s.students || 0), 0);
    const participations = evs.reduce((a, e) => a + (e.participants || 0), 0);
    const uniqueStudents = totalStudents > 0 ? Math.min(participations, totalStudents) : participations;
    const coveragePercent = totalStudents > 0 ? Math.round(uniqueStudents / totalStudents * 100) : 0;
    return {
      events:        evs.length,
      participations,
      prevention:    evs.filter(e => prevTypes.includes(e.type)).length,
      consultations: evs.filter(e => e.type === 'consultation').length,
      totalStudents,
      uniqueStudents,
      coveragePercent,
    };
  }

  /* Режим: статичні поля (base + всі журнальні заходи через recalcSchool) */
  let uniqueStudents = 0;
  schools.forEach(s => { uniqueStudents += window.calcCoverage(s).uniqueStudents; });
  const totalStudents  = schools.reduce((a, s) => a + (s.students     || 0), 0);
  const participations = schools.reduce((a, s) => a + (s.participants  || 0), 0);
  const coveragePercent = totalStudents > 0 ? Math.round(uniqueStudents / totalStudents * 100) : 0;
  return {
    events:        schools.reduce((a, s) => a + (s.events        || 0), 0),
    participations,
    prevention:    schools.reduce((a, s) => a + (s.prevention    || 0), 0),
    consultations: schools.reduce((a, s) => a + (s.consultations || 0), 0),
    totalStudents,
    uniqueStudents,
    coveragePercent,
  };
};

/* Зручний аліас: статистика по всіх обслуговуваних закладах */
window.calcTotalStats = () => window.calcStats();

/* Агрегована статистика заходів по 16 тематичних напрямках із monthlyData.
   Приймає необов'язковий список закладів (за замовчуванням — всі обслуговувані). */
window.calcCategoryStats = (schools) => {
  if (!schools) schools = (window.SOB.schools || []).filter(s => s.serviced && s.monthlyData);
  const totals = {};
  (window.SOB.eventCategories || []).forEach(c => { totals[c.id] = 0; });
  schools.forEach(s => {
    Object.entries(s.monthlyData || {}).forEach(([k, v]) => {
      if (k in totals) totals[k] = (totals[k] || 0) + (v || 0);
    });
  });
  return totals;
};

/* Статистика категорій із журнальних заходів (для режиму фільтру дат).
   Маппінг eventTypes → eventCategories за id де вони збігаються. */
window.calcCategoryStatsFromEvents = (events) => {
  const totals = {};
  (window.SOB.eventCategories || []).forEach(c => { totals[c.id] = 0; });
  (events || []).forEach(e => {
    const cat = e.category || e.type || '';
    if (cat in totals) totals[cat] = (totals[cat] || 0) + 1;
  });
  return totals;
};

/* ---- Авторизація ---- */
window.SOBAuth = {
  get(){ try { return JSON.parse(localStorage.getItem('sob_session') || 'null'); } catch(e){ return null; } },
  set(acc){ localStorage.setItem('sob_session', JSON.stringify(acc)); },
  clear(){ localStorage.removeItem('sob_session'); },
  async login(login, password){
    const hashBuf = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(password));
    const hash = Array.from(new Uint8Array(hashBuf)).map(b=>b.toString(16).padStart(2,'0')).join('');
    const acc = window.SOB.accounts.find(a => a.login === login && a.pwHash === hash);
    if(acc){
      const session = { login: acc.login, role: acc.role, name: acc.name, initials: acc.initials, inspector: acc.inspector };
      this.set(session); return session;
    }
    return null;
  },
  current(){ return this.get() || { role: 'public', name: 'Гість', initials: 'Г' }; },
  canEditSchool(schoolId){
    const u = this.current();
    if(u.role === 'admin') return true;
    if(u.role === 'inspector'){ const s = window.SOB.schools.find(x=>x.id===schoolId); return s && s.inspector === u.inspector; }
    return false;
  },
  canEdit(){ const r = this.current().role; return r==='admin' || r==='inspector'; }
};

/* ============================================================
   SOBDate — єдине джерело дат для всієї платформи
   ============================================================ */
window.SOBDate = (function(){
  const MN_FULL  = ['Січень','Лютий','Березень','Квітень','Травень','Червень','Липень','Серпень','Вересень','Жовтень','Листопад','Грудень'];
  const MN_SHORT = ['Січ','Лют','Бер','Кві','Тра','Чер','Лип','Сер','Вер','Жов','Лис','Гру'];

  function now(){ return new Date(); }
  function ym(d){ return d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0'); }
  function ymStr(d){ return MN_FULL[d.getMonth()]+' '+d.getFullYear(); }

  const today = now();
  const curYM  = ym(today);
  const curY   = today.getFullYear();
  const curM   = today.getMonth(); /* 0-based */

  /* Quarter boundaries */
  const qStart = new Date(curY, Math.floor(curM/3)*3, 1);

  /* First day of current month */
  const monthStart = curY+'-'+String(curM+1).padStart(2,'0')+'-01';
  /* Today ISO */
  const todayISO   = today.toISOString().slice(0,10);
  /* Yesterday ISO */
  const yesterdayISO = (()=>{ const d=new Date(today); d.setDate(d.getDate()-1); return d.toISOString().slice(0,10); })();

  /* prev month */
  const prevDate = new Date(curY, curM-1, 1);
  const prevYM   = ym(prevDate);
  const prevStr  = ymStr(prevDate);

  return {
    MN_FULL, MN_SHORT,
    now, ym, ymStr,
    today: todayISO,
    currentYM:   curYM,           /* "2026-06" */
    currentLabel: ymStr(today),   /* "Червень 2026" */
    prevYM,
    prevLabel:   prevStr,

    /* period labels for selectors */
    presets: [
      { id:'today',     label:'Сьогодні',        from: todayISO,  to: todayISO },
      { id:'yesterday', label:'Вчора',           from: yesterdayISO, to: yesterdayISO },
      { id:'week',      label:'Поточний тиждень', from: (()=>{ const d=new Date(today); d.setDate(d.getDate()-d.getDay()+1); return d.toISOString().slice(0,10); })(), to: todayISO },
      { id:'month',     label:'Поточний місяць',  ym:  curYM },
      { id:'prevmonth', label:'Попередній місяць',ym:  prevYM },
      { id:'quarter',   label:'Поточний квартал', from: qStart.toISOString().slice(0,10), to: todayISO },
      { id:'year',      label:'Поточний рік',     from: curY+'-01-01', to: todayISO },
      { id:'custom',    label:'Власний період',  custom: true },
      { id:'all',       label:'Весь час',         all: true },
    ],

    /* filter an events array by preset id */
    filterEvents(evs, presetId, customFrom, customTo){
      if(presetId === 'all' || !presetId) return evs;
      const p = this.presets.find(x=>x.id===presetId);
      if(!p) return evs;
      const from = customFrom || p.from || (p.ym ? p.ym+'-01' : null);
      const to   = customTo   || p.to   || (p.ym ? p.ym+'-31' : null);
      return evs.filter(e=>{
        if(!e.date) return false;
        if(from && e.date < from) return false;
        if(to   && e.date > to)   return false;
        return true;
      });
    },

    /* human-readable label for a preset */
    presetLabel(presetId){
      if(presetId==='month') return this.currentLabel;
      if(presetId==='prevmonth') return this.prevLabel;
      const p = this.presets.find(x=>x.id===presetId);
      return p ? p.label : presetId;
    }
  };
})();
